<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Pathfinders</title>
    <style>
        body {
            background: #1a1a1a;
            color: #eee;
            font-family: 'Segoe UI', Tahoma, Geneva, Res, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            margin: 0;
            height: 100vh;
            overflow: hidden;
        }
        #hud {
            display: flex;
            gap: 20px;
            margin-bottom: 15px;
            font-size: 1.2rem;
            background: #333;
            padding: 10px 25px;
            border-radius: 8px;
            box-shadow: 0 4px 10px rgba(0,0,0,0.5);
        }
        #maze {
            background: #000;
            border: 4px solid #444;
            border-radius: 4px;
            box-shadow: 0 0 20px rgba(0,0,0,0.8);
        }
        #controls {
            margin-top: 15px;
        }
        button {
            padding: 10px 25px;
            font-size: 1rem;
            cursor: pointer;
            background: #e74c3c;
            color: white;
            border: none;
            border-radius: 4px;
            transition: background 0.2s;
        }
        button:hover {
            background: #c0392b;
        }
        span {
            font-weight: bold;
            color: #2ecc71;
        }
    </style>
</head>
<body>

<div id="hud">
    <div>Completed: <span id="completed">0</span> / 24</div>
    <div>Time: <span id="timer">0</span>s</div>
</div>

<canvas id="maze" width="500" height="500"></canvas>

<div id="controls">
    <button id="reset">Reset Game</button>
</div>

<script>
(function() {
    const canvas = document.getElementById('maze');
    const ctx = canvas.getContext('2d');
    const completedEl = document.getElementById('padding'); // Not used, but for safety
    const completedText = document.getElementById('completed');
    const timerText = document.getElementById('timer');
    const resetBtn = document.getElementById('reset');

    const COLS = 20;
    const ROWS = 20;
    const CELL_SIZE = canvas.width / COLS;
    const TICK_MS = 150; // Simulation step duration in ms

    class Cell {
        constructor(x, y) {
            this.x = x;
            this.y = y;
            // Walls: top, right, bottom, left
            this.walls = { top: true, right: true, bottom: true, left: true };
            this.visited = false;
        }
    }

    class Bot {
        constructor(path) {
            this.path = path; // Array of {x, y}
            this.step = 0;
            this.x = path[0].x;
            this.y = path[0].y;
            this.finished = false;
        }
        move() {
            if (this.finished) return;
            this.step++;
            if (this.step < this.path.length) {
                this.x = this.path[this.step].x;
                this.y = this.path[this.step].y;
            } else {
                this.finished = true;
            }
        }
    }

    class GameEngine {
        constructor() {
            this.bots = [];
            this.completed = 0;
            this.elapsedMs = 0;
            this.cells = [];
            this.spawn = { x: 0, y: 0 };
            this.exit = { x: COLS - 1, y: ROWS - 1 };
            this.reset();
        }

        reset() {
            this.completed = 0;
            this.elapsedMs = 0;
            this.generateMaze();
            this.initBots();
            this.updateUI();
        }

        generateMaze() {
            this.cells = [];
            for (let y = 0; y < ROWS; y++) {
                for (let x = 0; x < COLS; x++) {
                    this.cells.push(new Cell(x, y));
                }
            }

            const stack = [];
            const startCell = this.cells[0];
            startCell.visited = true;
            stack.push(startCell);

            while (stack.length > 0) {
                const current = stack[stack.length - 1];
                const neighbors = this.getUnvisitedNeighbors(current);

                if (neighbors.length > 0) {
                    const next = neighbors[Math.floor(Math.random() * neighbors.length)];
                    this.removeWallBetween(current, next);
                    next.visited = true;
                    stack.push(next);
                } else {
                    stack.pop();
                }
            }

            // Add extra passages to create multiple paths (to avoid the "blob" effect)
            for (let i = 0; i < 30; i++) {
                const c1 = this.cells[Math.floor(Math.random() * this.cells.length)];
                const c2 = this.cells[arrayRandomIndex(this.cells)];
                if (this.isAdjacent(c1, c2)) {
                    this.removeWallBetween(c1, c2);
                }
            }
        }

        getUnvisitedNeighbors(cell) {
            const neighbors = [];
            const dirs = [{dx:0, dy:-1, wall:'top', opp:'bottom'}, {dx:1, dy:0, wall:'right', opp:'left'}, 
                         {dx:0, dy:1, wall:'bottom', opp:'top'}, {dx:-1, dy:0, wall:'left', opp:'right'}];

            for (const d of dirs) {
                const nx = cell.x + d.dx;
                const ny = cell.y + d.dy;
                if (nx >= 0 && nx < COLS && ny >= 0 && ny < ROWS) {
                    const neighbor = this.getCell(nx, ny);
                    if (!neighbor.visited) neighbors.push(neighbor);
                }
            }
            return neighbors;
        }

        removeWallBetween(c1, c2) {
            if (c1.x === c2.x) {
                if (c1.y > c2.y) { c1.walls.top = false; c2.walls.bottom = false; }
                else { c1.walls.bottom = false; c2.walls.top = false; }
            } else {
                if (c1.x > c2.x) { c1.walls.left = false; c2.walls.right = false; }
                else { c1.walls.right = false; c2.walls.left = false; }
            }
        }

        isAdjacent(c1, c2) {
            return Math.abs(c1.x - c2.x) + Math.abs(c1.y - c2.y) === 1;
        }

        getCell(x, y) {
            return this.cells[y * COLS + x];
        }

        initBots() {
            // BFS to find distances from exit for pathfinding
            const dists = new Array(COLS * ROWS).fill(Infinity);
            const queue = [this.exit.y * COLS + this.exit.x];
            dists[this.exit.y * COLS + this.exit.x] = 0;

            let head = 0;
            while (head < queue.length) {
                const idx = queue[head++];
                const curr = this.cells[idx];
                const neighbors = [
                    {x: curr.x, y: curr.y-1, wall:'top'}, {x: curr.x+1, y: curr.y, wall:'right'},
                    {x: curr.x, y:curr.y+1, wall:'bottom'}, {x: curr.x-1, y:curr.y, wall:'left'}
                ];

                for (const n of neighbors) {
                    if (n.x >= 0 && n.x < COLS && n.y >= 0 && n.y < ROWS) {
                        const neighbor = this.getCell(n.x, n.y);
                        // Check if there is no wall blocking the path
                        let blocked = false;
                        if (n.wall === 'top' && curr.walls.top) blocked = true;
                        if (n.wall === 'right' && curr.walls.right) blocked = true;
                        if (n.wall === 'bottom' && curr.walls.bottom) blocked = true;
                        if (n.wall === 'left' && curr.walls.left) blocked = true;

                        if (!blocked && dists[neighbor.y * COLS + neighbor.x] === Infinity) {
                            dists[neighbor.y * COLS + neighbor.x] = dists[idx] + 1;
                            queue.push(neighbor.y * COLS + neighbor.x);
                        }
                    }
                }
            }

            this.bots = Array.from({ length: 24 }, () => {
                const path = this.generateRandomShortestPath(dists);
                return new Bot(path);
            });
        }

        generateRandomShortestPath(dists) {
            let currX = this.spawn.x;
            let currY = this.spawn.y;
            const path = [{x: currX, y: currY}];

            while (currX !== this.exit.x || currY !== this.exit.y) {
                const neighbors = [
                    {x: currX, y: currY-1}, {x: currX+1, y: currY},
                    {x: currX, y: currY+1}, {x: currX-1, y: currY}
                ];
                const valid = neighbors.filter(n => 
                    n.x >= 0 && n.x < COLS && n.y >= 0 && n.y < ROWS &&
                    dists[n.y * COLS + n.x] === dists[currY * COLS + currX] - 1 &&
                    this.canMove(currX, currY, n.x, n.y)
                );

                if (valid.length === 0) break; // Should not happen in solvable maze
                const next = valid[Math.floor(Math.random() * valid.length)];
                currX = next.x;
                currY = next.y;
                path.push({x: currX, y: currY});
            }
            return path;
        }

        canMove(x1, y1, x2, y2) {
            const c1 = this.getCell(x1, y1);
            if (x1 === x2) {
                if (y1 < y2 && c1.walls.bottom) return false;
                if (y1 > y2 && c1.walls.top) return false;
            } else {
                if (x1 < x2 && c1.walls.right) return false;
                if (x1 > x2 && c1.walls.left) return false;
            }
            return true;
        }

        tick(n) {
            for (let i = 0; i < n; i++) {
                this._step();
            }
            this.updateUI();
        }

        _step() {
            this.elapsedMs += TICK_MS;
            let newlyFinished = 0;
            for (const bot of this.bots) {
                if (!bot.finished) {
                    bot.move();
                    if (bot.finished) newlyFinished++;
                }
            }
            this.completed += newlyFinshedCount(newlyFinished); // Helper to avoid scope issues
        }

        // Internal helper for the step logic
        updateUI() {
            completedText.textContent = this.completed;
            timerText.textContent = (this.elapsedMs / 1000).toFixed(1);
        }
    }

    // Helper functions to keep scope clean
    function arrayRandomIndex(arr) { return Math.floor(Math.random() * arr.length); }
    function newlyFinishedCount(n) { return n; }

    const game = new GameEngine();

    // Expose API for grading
    window.game = {
        get bots() { return game.bots; },
        get completed() { return game.completed; },
        get elapsedMs() { return game.elapsedMs; },
        tick: (n) => game.tick(n),
        reset: () => game.reset()
    };

    // Rendering loop
    function draw() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // Draw Walls
        ctx.strokeStyle = "#fff";
        ctx.lineWidth = 2;
        ctx.beginPath();
        game.cells.forEach(c => {
            const x = c.x * CELL_SIZE;
            const y = c.y * CELL_SIZE;
            if (c.walls.top) { ctx.moveTo(x, y); ctx.lineTo(x + CELL_SIZE, y); }
            if (c.walls.right) { ctx.moveTo(x + CELL_SIZE, y); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE); }
            if (c.walls.bottom) { ctx.moveTo(x, y + CELL_SIZE); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE); }
            if (cellsLeft(c)) {} // placeholder
            if (c.walls.left) { ctx.moveTo(x, y); ctx.lineTo(x, y + CELL_SIZE); }
        });
        ctx.stroke();

        // Draw Exit/Spawn markers
        ctx.fillStyle = "rgba(46, 204, 113, 0.3)"; // Spawn green
        ctx.fillRect(game.spawn.x * CELL_SIZE, game.spawn.y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
        ctx.fillStyle = "rgba(231, 76, 60, 0.3)"; // Exit red
        ctx.fillRect(game.exit.x * CELL_SIZE, game.exit.y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

        // Draw Bots
        game.bots.forEach((bot, i) => {
            ctx.fillStyle = `hsl(${(i * 15) % 360}, 70%, 60%)`;
            ctx.beginPath();
            const bx = bot.x * CELL_SIZE + CELL_SIZE / 2;
            const by = bot.y * CELL_SIZE + CELL_SIZE / 2;
            ctx.arc(bx, by, CELL_SIZE / 3, 0, Math.PI * 2);
            ctx.fill();
        });

        requestAnimationFrame(draw);
    }

    function cellsLeft(c) { return false; } // dummy

    // Simulation loop (runs the game logic independently of rendering)
    setInterval(() => {
        game._step();
        game.updateUI();
    }, TICK_MS);

    resetBtn.addEventListener('click', () => game.reset());

    draw();
})();
</script>
</body>
</html>
